// Parse Haiku's JSON, validate the rubric schema. Throw on invalid so the error
// output routes to the score_failed logger (never force a default score).
const body = $json;
let text = '';
try { text = (body.content || []).filter(b => b.type === 'text').map(b => b.text).join(''); } catch (e) {}
let parsed;
try { parsed = JSON.parse((text || '').replace(/```json|```/g, '').trim()); }
catch (e) { throw new Error('malformed_json_from_haiku'); }
const ss = parsed.subscores || {};
for (const k of ['revenue','margin','list','growth','authority']) {
  const v = ss[k];
  if (!Number.isInteger(v) || v < 1 || v > 5) throw new Error('bad_subscore_' + k);
}
const total = parsed.total;
if (!Number.isInteger(total) || total < 5 || total > 25) throw new Error('bad_total');
const sum = ['revenue','margin','list','growth','authority'].reduce((a,k)=>a+ss[k],0);
if (sum !== total) throw new Error('total_mismatch_' + sum + '_vs_' + total);
const queue = total >= 20 ? 'hot' : total >= 15 ? 'warm' : total >= 10 ? 'cold' : 'archive';
return [{ json: { lead_id: $('Loop').item.json.lead_id, subscores: ss, total, reasoning: (parsed.reasoning || ''), queue } }];
